function LxGameCtrl:InitAfterLoginGame()
    self:InitAfterLoginGameEvents()
    self:InitZeroTimeClock()

    self._isInitAfterLoginGame = true
end

function LxGameCtrl:InitAfterLoginGameEvents()
    if self._isInitAfterLoginGame then return end

    self:AddEventHandler(EventNames.NET_LOST, self.OnNetLost, self)

    self:AddEventHandler(EventNames.REWARDS_RECEIVED, self.OnRewardsReceived, self)
    self:AddEventHandler(EventNames.SHOW_TIPS, self.OnShowTips, self)
    self:AddEventHandler(EventNames.ON_PANEL_CLOSED, self.OnPanelClosed, self)
    self:AddEventHandler(EventNames.GUIDE_FINISH, self.InternalCheckPopPanel, self)
    self:AddEventHandler(EventNames.ON_NEWBIE_FINISHED,self.OnNewBieFinished,self)
    self:AddEventHandler(EventNames.LEVEL_LOAD_OK, self.OnLevelLoadOK, self)
end
function LxGameCtrl:OnNewBieFinished()

    self:InternalCheckPopPanel()

end
function LxGameCtrl:OnNetLost()
    self:StopZeroTimeClock()
end

---region 零点计时逻辑
function LxGameCtrl:StopZeroTimeClock()
    self:StopTimer("clock")
end

function LxGameCtrl:InitZeroTimeClock()
    if self._nextZeroTime == nil then
        self:CalcZeroTime(GetTimestamp())
    end

    if not self:FindTimer("clock") then
        self:StartTimer("clock", 1,false,-1,function()
            self:RunZeroTimeClock()
        end)
    end
end

function LxGameCtrl:CalcZeroTime(time)
    local sDate = LxUtil.OSDate("*t", time)
    sDate.hour = 0
    sDate.min = 0
    sDate.sec = 0
    local zeroTime = LxUtil.OSTime(sDate) + 86400
    if not self._nextZeroTime or zeroTime > self._nextZeroTime then
        self._nextZeroTime = zeroTime
    end
end

function LxGameCtrl:RunZeroTimeClock()
    if not self._nextZeroTime then return end
    local time = GetTimestamp()
    if time > self._nextZeroTime then
        local oldZeroTime = self._nextZeroTime
        self:CalcZeroTime(time)
        if self._nextZeroTime > oldZeroTime then
            FireEvent(EventNames.ZERO_TIME_PASS)
        end
    end
end
---endregion 零点计时逻辑


---region -- alert弹窗逻辑
function LxGameCtrl:OnAlertSet(alertRemainType, id, sid)
    alertRemainType = tostring(alertRemainType)
    id = tostring(id)
    if not string.isempty(sid) then
        id = id.."_"..sid
    end
    ModuleCenter.Game:SetAlert(alertRemainType, id)
end

function LxGameCtrl:OnAlertShow(params, addPop)
    local refData = GameTable.WindowTipRef[params.refId]
    if not refData then
        if LOG_INFO_ENABLED then
            printError("gamectrl", "refId = %s 不存在, 默认执行ok选择 ", tostring(params.refId))
        end
        if params.actionOk then
            params.actionOk()
        end
        return
    end
    local alertId = tostring(params.refId)
    if not string.isempty(params.sid) then
        alertId = alertId.."_"..params.sid
    end
    local remind = refData.remind
    local isAlert = true
    if not string.isempty(remind) then
        local bRemiand,alertRemainType,_a2 = string.match(remind, "(%d+)=(%d+)=(%d+)")
        alertRemainType = tostring(alertRemainType)
        bRemiand = checknumber(bRemiand)

        local gameModule = ModuleCenter.Game
        if bRemiand and bRemiand > 0 then
            local isExpire = gameModule:IsTimeExpire(alertRemainType, os.time())
            if isExpire then
                gameModule:ClearAlert(alertRemainType)
                isAlert = true
            else
                isAlert = gameModule:IsAlert(alertRemainType, alertId)
            end
            --else
            --    isAlert = gameModule:IsAlert(alertRemainType, alertId)
        end
    end
    if isAlert then
        if addPop then
            self:TryPopPanel(LxUiHelper.GenUiKey(UiNames.Alert,tostring(alertId)), params)
        else
            ShowPanel(LxUiHelper.GenUiKey(UiNames.Alert,tostring(alertId)), params)
        end
    else
        if LOG_INFO_ENABLED then
            printInfo("gamectrl", "不再提示， 默认执行ok选择 ", tostring(params.refId))
        end
        if params.actionOk then
            params.actionOk()
        end
    end
end


--- 拓展，不归 WindowTipRef 控制
---@field remind number 与 WindowTipRef 配置一致，配置格式：是否需要提醒=提醒频率类型=勾选项默认状态
function LxGameCtrl:OnAlertExtraShow(params, addPop)
    local alertKey = params.alertKey

    local isAlert = true
    local remind = params.remind
    if not string.isempty(remind) then
        local bRemiand,alertRemainType,_a2 = string.match(remind, "(%d+)=(%d+)=(%d+)")
        alertRemainType = tostring(alertRemainType)
        bRemiand = checknumber(bRemiand)
        local gameModule = ModuleCenter.Game
        if bRemiand and bRemiand > 0 then
            local isExpire = gameModule:IsExtraTimeExpire(alertRemainType, os.time())
            if isExpire then
                gameModule:ClearExtraAlert(alertRemainType)
                isAlert = true
            else
                isAlert = gameModule:IsExtraAlert(alertRemainType, alertKey)
            end
        end
    end
    if isAlert then
        local uiKey = params.uiKey
        if addPop then
            self:TryPopPanel(uiKey, params)
        else
            ShowPanel(uiKey, params)
        end
    else
        if LOG_INFO_ENABLED then
            printInfo("gamectrl", "不再提示， 默认执行ok选择 ", tostring(params.refId))
        end
        if params.actionOk then
            params.actionOk()
        end
    end
end


function LxGameCtrl:OnAlertExtraSet(alertRemainType, id, sid)
    alertRemainType = tostring(alertRemainType)
    id = tostring(id)
    if not string.isempty(sid) then
        id = id.."_"..sid
    end
    ModuleCenter.Game:SetExtraAlert(alertRemainType, id)
end
