---region 奖励飘动逻辑
---@param thingsInfo LxThingsInfo
function LxGameCtrl:OnRewardsReceived(type, thingsInfo,extra)
    extra = extra or {}

    local itemDatas = {}
    local itemType = ThingType.Item
    for k,v in ipairs(thingsInfo.items or {}) do
       table.insert(itemDatas, {type=itemType, refId = v.refId, num = checknumber(v.num)})
    end

    itemType = ThingType.Hero
    local isShowHero = false
    for k,v in ipairs(thingsInfo.heroes or {}) do
        table.insert(itemDatas, {type=itemType, refId = v.refId, num = 1})
        isShowHero = true
    end

    itemType = ThingType.Equip
    for k,v in ipairs(thingsInfo.equips or {}) do
        table.insert(itemDatas, {type=itemType, refId = v.refId, num = 1})
    end

    itemType = ThingType.People
    for k,v in ipairs(thingsInfo.peoples or {}) do
        table.insert(itemDatas, {type=itemType, refId = v.refId, num = 1})
    end

    itemType = ThingType.Soldier
    for k,v in ipairs(thingsInfo.soldiers or {}) do
        table.insert(itemDatas, {type=itemType, refId = v.key, num = v.value})
    end
    

    

    if #itemDatas == 0 then return end

    if thingsInfo.windowType == 0 then
        local mode = ModuleCenter.Hero:GetCurMode()

        local funC = function()
            ShowPanel(UiNames.Prize, {
                prizes = itemDatas,
                type = type,
                extra = extra,
            })
        end
        if mode == HeroModeType.Compete and isShowHero then
            local data = {
                showHeroList = thingsInfo.heroes,
                callBackFunc = funC,
            }

            local uiKey = UiNames.HeroCallHighQuality
            if IsOpenPanel(uiKey) then
                RefreshPanel(uiKey,data)
            else
                ShowPanel(uiKey,data)
            end
        else
            funC()
        end

    elseif thingsInfo.windowType == 1 then
        self:SysMsgShowImpl(itemDatas, 1)
    end
end
---endregion 奖励飘动逻辑

---region 弹窗tips逻辑
function LxGameCtrl:OnShowTips(tipsData)
    if tipsData.type == ThingType.Item then
        local key = UiNames.ItemTips
        if tipsData.from == key then
            key = key.."_"..tostring(tipsData.fromData)
        end
        ShowPanel(key, tipsData)
    elseif tipsData.type == ThingType.Hero then
        ---@type LxHeroObj
        local heroObj = tipsData.heroObj
        local detail = heroObj ~= nil
        if detail then
            CtrlCenter.Hero:OpenHeroInfoDisplay(heroObj)
        else
            --CtrlCenter.Hero:OpenInitHeroInfoDisplay(tipsData.refId)
            CtrlCenter.HeroBook:OpenPreviewHeroMax(tipsData.refId)
        end
    elseif tipsData.type == ThingType.Equip then
        ShowPanel(UiNames.EquipTips, {refId = tipsData.refId, fromView = 1})
    elseif tipsData.type == ThingType.People then
        local itemPos = tipsData.itemPos
        ShowPanel(UiNames.PeopleTips, {refId = tipsData.refId, headPos = itemPos})
    elseif tipsData.type == ThingType.Soldier then
        local itemPos = tipsData.itemPos
        ShowPanel(UiNames.SoldierTips, {refId = tipsData.refId, soldierPos = itemPos})
    end
end
---endregion 弹窗tips逻辑

---region 自动弹窗逻辑
function LxGameCtrl:IsAllowPopPanel(data)
    local uiName = data.uiName
    if not table.isempty(self._openPopNames) then
        return false
    end
    local ctrl = MgrCenter.PanelMgr:GetPanelCtrl(uiName)
    if ctrl and not ctrl:IsDisposed() then
        return false
    end
    --if not CtrlCenter.Guide:IsEnterCity() then
    --    return false
    --end
    if CtrlCenter.Guide:HasGuideOrWaitGuide() then
        return false
    end
    if CtrlCenter.Battle:IsHaveAnyBattleShow() then
        return false
    end
    local t = ModuleCenter.Story:GetLastSceneId()
    local storyRun = ModuleCenter.Story:IsNewbieRunning()
    --local pass = CtrlCenter.Story:StoryTriggerIsEnd(GameTable.StorylineConfigRef.tipsStory)
    if(storyRun or t > 0)then
        return false
    end
    return true
end

function LxGameCtrl:InternalCheckPopPanel()
    local datas = self._popDataList
    local len = #datas
    if len == 0 then return end
    local idx = nil
    for k,v in ipairs(datas) do
        if self:IsAllowPopPanel(v) then
            idx = k
            break
        end
    end
    if not idx then
        return
    end
    local data = datas[idx]
    table.remove(datas, idx)
    self:InternalDoPopPanel(data)
end

function LxGameCtrl:InternalDoPopPanel(data)
    self._openPopNames[data.uiKey] = true
    ShowPanel(data.uiKey, data.para)
end

function LxGameCtrl:InternalAddPopPanel(uiKey, para)
    local uiName = LxUiHelper.GetUiNameByUiKey(uiKey)
    local popData = {
        uiKey = uiKey,
        uiName = uiName,
        para = para,
    }
    table.insert(self._popDataList, popData)
end

function LxGameCtrl:TryPopPanel(uiName, para)
    self:InternalAddPopPanel(uiName, para)
    self:InternalCheckPopPanel()
end

function LxGameCtrl:InternalRemovePopPanel(uiName)
    local datas = self._popDataList
    local idx = nil
    for k,v in ipairs(datas) do
        if v.uiName == uiName then
            idx = k
            break
        end
    end
    if not idx then
        return
    end
    table.remove(datas, idx)
end

function LxGameCtrl:RemovePopPanelByParams(uiName, paramKey, paramValue)
    local datas = self._popDataList
    local idx = nil
    for k,v in ipairs(datas) do
        if v.uiName == uiName then
            local para = v.para
            if para and type(para) == "table" and para[paramKey] == paramValue then
                idx = k
                break
            end
        end
    end
    if not idx then
        return
    end
    table.remove(datas, idx)
end

function LxGameCtrl:OnPanelClosed(uiKey, uiName, uiPrefabName)
    if self._openPopNames[uiKey] then
        self._openPopNames[uiKey] = nil
        self:InternalCheckPopPanel()
        FireEvent(EventNames.GUIDE_CHECK_START_WAIT)
    end
end

function LxGameCtrl:OnLevelLoadOK(levelName)
    if levelName == LevelNames.Main or levelName == LevelNames.DreamTrip then
        self:InternalCheckPopPanel()
    end
end

---@region 动态降帧率
function LxGameCtrl:OnTouchScreen()
    if not self._isTouchScreen then
        if MgrCenter.GameMgr then
            MgrCenter.GameMgr:SetTouchFrameRate(true)
        end
        self._isTouchScreen = true
    end
    self._downFrameRateTime = Time.realtimeSinceStartup + 60
    if not self:FindTimer("_downRate") then
        self:StartTimer("_downRate", 1,false,-1,function()
            self:MonitorTouchScreen()
        end)
    end
end

function LxGameCtrl:MonitorTouchScreen()
    if self._downFrameRateTime then
        if self._downFrameRateTime <= Time.realtimeSinceStartup then
            self._isTouchScreen = false
            self._downFrameRateTime = nil
            if CtrlCenter.Battle and CtrlCenter.Battle:IsHaveAnyBattleShow() then
                ---战斗不降速
                return
            end
            if MgrCenter.GameMgr then
                MgrCenter.GameMgr:SetTouchFrameRate(false)
            end
        end
    end
end
---@endregion 动态降帧率

return LxGameCtrl